#include <stdio.h>
#include <stdlib.h>
#include <limits.h>

int maxColors(int *values, int *colors, int n, long long s) {
    int *dp = (int *)calloc(s + 1, sizeof(int));
    dp[0] = 0;
    for (int i = 1; i <= s; i++) {
        dp[i] = -1;
    }
    for (int i = 0; i < n; i++) {
        for (int j = values[i]; j <= s; j++) {
            if (dp[j - values[i]] != -1) {
                if (dp[j] == -1 || dp[j - values[i]] + 1 > dp[j]) {
                    dp[j] = dp[j - values[i]] + 1;
                }
            }
        }
    }
    int max = dp[s];
    free(dp);
    return max;
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n;
        scanf("%d", &n);
        int *values = (int *)malloc(n * sizeof(int));
        int *colors = (int *)malloc(n * sizeof(int));
        for (int i = 0; i < n; i++) {
            scanf("%d %d", &values[i], &colors[i]);
        }
        int q;
        scanf("%d", &q);
        for (int i = 0; i < q; i++) {
            long long s;
            scanf("%lld", &s);
            printf("%d\n", maxColors(values, colors, n, s));
        }
        free(values);
        free(colors);
    }
    return 0;
}

