import java.util.Scanner;

public class Main {
    public static int maxColors(int[] values, int[] colors, int n, long s) {
        int[] dp = new int[(int)s + 1];
        for (int i = 0; i <= s; i++) {
            dp[i] = -1;
        }
        dp[0] = 0;
        for (int i = 0; i < n; i++) {
            for (int j = values[i]; j <= s; j++) {
                if (dp[j - values[i]] != -1) {
                    if (dp[j] == -1 || dp[j - values[i]] + 1 > dp[j]) {
                        dp[j] = dp[j - values[i]] + 1;
                    }
                }
            }
        }
        return dp[(int)s];
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int t = scanner.nextInt();
        while (t-- > 0) {
            int n = scanner.nextInt();
            int[] values = new int[n];
            int[] colors = new int[n];
            for (int i = 0; i < n; i++) {
                values[i] = scanner.nextInt();
                colors[i] = scanner.nextInt();
            }
            int q = scanner.nextInt();
            for (int i = 0; i < q; i++) {
                long s = scanner.nextLong();
                System.out.println(maxColors(values, colors, n, s));
            }
        }
    }
